'use client'

import { Input } from '@/components/ui/input'
import { motion } from 'framer-motion'
import { Search as SearchIcon } from 'lucide-react'

const Search = () => {
  return (
    <motion.header
      initial={{ opacity: 0, y: 30 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.6, delay: 0.2 }}
      className="relative py-20 px-4 text-center bg-cover bg-center"
      style={{ backgroundImage: "url('/images/houses.png')" }}
    >
      <div className="absolute inset-0 bg-black/40" />
      <h1 className="text-4xl md:text-6xl font-bold text-white mb-4 relative z-10">
        Search it. Explore it. Buy it.
      </h1>
      <p className="text-lg text-gray-200 mb-8 max-w-2xl mx-auto relative z-10">
        Find your dream property from thousands of listings
      </p>
      <div className="relative max-w-xl mx-auto z-10">
        <SearchIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
        <Input
          type="text"
          placeholder="Enter an address, neighborhood, city, or ZIP code"
          className="pl-10 h-12 text-base bg-white"
        />
      </div>
    </motion.header>
  )
}

export default Search
