'use client'

import { useState, useEffect, useRef } from 'react'
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog'
import { Wallet } from 'lucide-react'

export default function WalletModal({ open, onOpenChange, onConnect }) {
  const [providers, setProviders] = useState([])
  const [done, setDone] = useState(false)
  const [connecting, setConnecting] = useState(null)
  const providersRef = useRef([])
  const timerRef = useRef(null)

  useEffect(() => {
    if (!open) {
      setProviders([])
      setDone(false)
      setConnecting(null)
      providersRef.current = []
      return
    }

    providersRef.current = []
    setDone(false)
    setConnecting(null)

    const handler = (event) => {
      const exists = providersRef.current.some(p => p.info.uuid === event.detail.info.uuid)
      if (!exists) {
        providersRef.current = [...providersRef.current, event.detail]
        setProviders([...providersRef.current])
      }
    }

    window.addEventListener('eip6963:announceProvider', handler)
    window.dispatchEvent(new Event('eip6963:requestProvider'))

    timerRef.current = setTimeout(() => {
      setDone(true)
    }, 3000)

    return () => {
      window.removeEventListener('eip6963:announceProvider', handler)
      if (timerRef.current) clearTimeout(timerRef.current)
    }
  }, [open])

  const handleClick = async (p) => {
    const id = p.info.uuid || p.info.rdns
    setConnecting(id)
    try {
      await onConnect(p)
      onOpenChange(false)
    } catch (err) {
      console.error(err)
    }
    setConnecting(null)
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-sm">
        <DialogHeader>
          <DialogTitle>Connect a Wallet</DialogTitle>
          <DialogDescription>
            Choose which wallet to connect
          </DialogDescription>
        </DialogHeader>
        <div className="flex flex-col gap-2 py-2">
          {!done && providers.length === 0 ? (
            <div className="text-sm text-muted-foreground text-center py-8">
              Looking for wallets...
            </div>
          ) : providers.length === 0 ? (
            <div className="text-sm text-muted-foreground text-center py-8">
              No wallet extensions found.{' '}
              <a href="https://metamask.io" target="_blank" rel="noreferrer" className="underline">
                Install one
              </a>
            </div>
          ) : (
            providers.map((p) => {
              const id = p.info.uuid || p.info.rdns
              return (
                <button
                  key={id}
                  onClick={() => handleClick(p)}
                  disabled={connecting === id}
                  className="flex items-center gap-3 rounded-lg border p-3 hover:bg-muted transition-colors text-left disabled:opacity-50"
                >
                  {p.info.icon ? (
                    <img src={p.info.icon} alt="" className="w-9 h-9 rounded-lg" />
                  ) : (
                    <div className="w-9 h-9 rounded-lg bg-muted flex items-center justify-center">
                      <Wallet className="w-5 h-5" />
                    </div>
                  )}
                  <div className="flex-1 min-w-0">
                    <p className="font-medium text-sm">{p.info.name}</p>
                    {p.info.rdns && (
                      <p className="text-xs text-muted-foreground truncate">{p.info.rdns}</p>
                    )}
                  </div>
                  {connecting === id && (
                    <div className="w-4 h-4 border-2 border-primary border-t-transparent rounded-full animate-spin shrink-0" />
                  )}
                </button>
              )
            })
          )}
        </div>
      </DialogContent>
    </Dialog>
  )
}
