'use client'

import { ethers } from 'ethers'
import { useEffect, useState } from 'react'
import Image from 'next/image'
import { motion, AnimatePresence } from 'framer-motion'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { X, Bed, Bath, Maximize, MapPin, DollarSign, Home as HomeIcon, Shield, CheckCircle, XCircle } from 'lucide-react'

const Home = ({ home, provider, account, escrow, togglePop }) => {
  const [hasBought, setHasBought] = useState(false)
  const [hasLended, setHasLended] = useState(false)
  const [hasInspected, setHasInspected] = useState(false)
  const [hasSold, setHasSold] = useState(false)

  const [buyer, setBuyer] = useState(null)
  const [lender, setLender] = useState(null)
  const [inspector, setInspector] = useState(null)
  const [seller, setSeller] = useState(null)

  const [owner, setOwner] = useState(null)

  const fetchDetails = async () => {
    const buyer = await escrow.buyer(home.id)
    setBuyer(buyer)

    const hasBought = await escrow.approval(home.id, buyer)
    setHasBought(hasBought)

    const seller = await escrow.seller()
    setSeller(seller)

    const hasSold = await escrow.approval(home.id, seller)
    setHasSold(hasSold)

    const lender = await escrow.lender()
    setLender(lender)

    const hasLended = await escrow.approval(home.id, lender)
    setHasLended(hasLended)

    const inspector = await escrow.inspector()
    setInspector(inspector)

    const hasInspected = await escrow.inspectionPassed(home.id)
    setHasInspected(hasInspected)
  }

  const fetchOwner = async () => {
    if (await escrow.isListed(home.id)) return

    const owner = await escrow.buyer(home.id)
    setOwner(owner)
  }

  const buyHandler = async () => {
    const escrowAmount = await escrow.escrowAmount(home.id)
    const ethersProvider = new ethers.providers.Web3Provider(provider)
    const signer = await ethersProvider.getSigner()

    let transaction = await escrow.connect(signer).depositEarnest(home.id, { value: escrowAmount })
    await transaction.wait()

    transaction = await escrow.connect(signer).approveSale(home.id)
    await transaction.wait()

    setHasBought(true)
  }

  const inspectHandler = async () => {
    const ethersProvider = new ethers.providers.Web3Provider(provider)
    const signer = await ethersProvider.getSigner()

    const transaction = await escrow.connect(signer).updateInspectionStatus(home.id, true)
    await transaction.wait()

    setHasInspected(true)
  }

  const lendHandler = async () => {
    const ethersProvider = new ethers.providers.Web3Provider(provider)
    const signer = await ethersProvider.getSigner()

    const transaction = await escrow.connect(signer).approveSale(home.id)
    await transaction.wait()

    const lendAmount = (await escrow.purchasePrice(home.id) - await escrow.escrowAmount(home.id))
    await signer.sendTransaction({ to: escrow.address, value: lendAmount.toString(), gasLimit: 60000 })

    setHasLended(true)
  }

  const sellHandler = async () => {
    const ethersProvider = new ethers.providers.Web3Provider(provider)
    const signer = await ethersProvider.getSigner()

    let transaction = await escrow.connect(signer).approveSale(home.id)
    await transaction.wait()

    transaction = await escrow.connect(signer).finalizeSale(home.id)
    await transaction.wait()

    setHasSold(true)
  }

  useEffect(() => {
    fetchDetails()
    fetchOwner()
  }, [hasSold])

  const getStatusIcon = (isDone) => isDone ? <CheckCircle className="w-4 h-4 text-green-500" /> : <XCircle className="w-4 h-4 text-gray-300" />

  return (
    <Dialog open onOpenChange={togglePop}>
      <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="text-2xl font-bold">{home.name}</DialogTitle>
        </DialogHeader>

        <div className="grid md:grid-cols-2 gap-6">
          <div className="relative aspect-video rounded-lg overflow-hidden">
            <Image
              src={home.image || '/images/houses.png'}
              alt={home.name}
              fill
              className="object-cover"
            />
          </div>

          <div>
            <div className="flex items-center gap-3 mb-4">
              <Badge variant="secondary" className="flex items-center gap-1">
                <Bed className="w-3 h-3" />
                {home.attributes?.[2]?.value || 'N/A'} bds
              </Badge>
              <Badge variant="secondary" className="flex items-center gap-1">
                <Bath className="w-3 h-3" />
                {home.attributes?.[3]?.value || 'N/A'} ba
              </Badge>
              <Badge variant="secondary" className="flex items-center gap-1">
                <Maximize className="w-3 h-3" />
                {home.attributes?.[4]?.value || 'N/A'} sqft
              </Badge>
            </div>

            <div className="flex items-center gap-1 text-sm text-gray-500 mb-4">
              <MapPin className="w-4 h-4" />
              <span>{home.address}</span>
            </div>

            <p className="text-3xl font-bold text-primary mb-6">
              {home.attributes?.[0]?.value || '0'} ETH
            </p>

            {owner ? (
              <div className="flex items-center gap-2 p-3 bg-muted rounded-lg mb-6">
                <HomeIcon className="w-5 h-5 text-primary" />
                <span className="text-sm">
                  Owned by {owner.slice(0, 6)}...{owner.slice(38, 42)}
                </span>
              </div>
            ) : (
              <div className="space-y-3 mb-6">
                {account === inspector ? (
                  <Button onClick={inspectHandler} disabled={hasInspected} className="w-full">
                    <Shield className="w-4 h-4 mr-2" />
                    {hasInspected ? 'Inspected' : 'Approve Inspection'}
                  </Button>
                ) : account === lender ? (
                  <Button onClick={lendHandler} disabled={hasLended} className="w-full">
                    <DollarSign className="w-4 h-4 mr-2" />
                    {hasLended ? 'Approved' : 'Approve & Lend'}
                  </Button>
                ) : account === seller ? (
                  <Button onClick={sellHandler} disabled={hasSold} className="w-full">
                    {hasSold ? 'Sold' : 'Approve & Sell'}
                  </Button>
                ) : (
                  <Button onClick={buyHandler} disabled={hasBought} className="w-full">
                    {hasBought ? 'Bought' : 'Buy'}
                  </Button>
                )}

                <Button variant="outline" className="w-full">
                  Contact agent
                </Button>
              </div>
            )}

            <div className="flex items-center gap-4 text-sm">
              <span className="flex items-center gap-1">{getStatusIcon(hasBought)} Buyer</span>
              <span className="flex items-center gap-1">{getStatusIcon(hasLended)} Lender</span>
              <span className="flex items-center gap-1">{getStatusIcon(hasInspected)} Inspection</span>
              <span className="flex items-center gap-1">{getStatusIcon(hasSold)} Seller</span>
            </div>
          </div>
        </div>

        <div className="mt-6">
          <h3 className="text-lg font-semibold mb-2">Overview</h3>
          <p className="text-gray-600">{home.description}</p>
        </div>

        <div className="mt-4">
          <h3 className="text-lg font-semibold mb-2">Facts and features</h3>
          <div className="grid grid-cols-2 md:grid-cols-3 gap-2">
            {home.attributes?.map((attribute, index) => (
              <div key={index} className="p-2 bg-muted rounded-md">
                <p className="text-xs text-muted-foreground">{attribute.trait_type}</p>
                <p className="text-sm font-medium">{attribute.value}</p>
              </div>
            ))}
          </div>
        </div>
      </DialogContent>
    </Dialog>
  )
}

export default Home
