'use client'

import { useState, useRef, useEffect } from 'react'
import { ethers } from 'ethers'
import Image from 'next/image'
import Link from 'next/link'
import { Button } from '@/components/ui/button'
import { motion } from 'framer-motion'
import { Home, Search, Building2, Wallet, LogOut, Copy, ChevronDown } from 'lucide-react'
import WalletModal from './WalletModal'

const Navigation = ({ account, setAccount, setProvider }) => {
  const [walletModalOpen, setWalletModalOpen] = useState(false)
  const [dropdownOpen, setDropdownOpen] = useState(false)
  const dropdownRef = useRef(null)

  useEffect(() => {
    const handleClick = (e) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setDropdownOpen(false)
      }
    }
    document.addEventListener('mousedown', handleClick)
    return () => document.removeEventListener('mousedown', handleClick)
  }, [])

  const connectHandler = () => {
    setWalletModalOpen(true)
  }

  const handleWalletSelect = async (providerInfo) => {
    const ethersProvider = new ethers.providers.Web3Provider(providerInfo.provider)
    const accounts = await ethersProvider.send('eth_requestAccounts', [])
    setAccount(accounts[0])
    if (setProvider) setProvider(ethersProvider)
  }

  const disconnectHandler = () => {
    setAccount(null)
    setProvider(null)
    setDropdownOpen(false)
  }

  const copyAddress = () => {
    if (account) {
      navigator.clipboard.writeText(account)
      setDropdownOpen(false)
    }
  }

  return (
    <>
      <motion.nav
      initial={{ y: -80 }}
      animate={{ y: 0 }}
      transition={{ duration: 0.5 }}
      className="fixed top-0 left-0 right-0 z-50 bg-white/80 backdrop-blur-md border-b"
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-16">
          <div className="flex items-center gap-8">
            <div className="hidden md:flex items-center gap-6">
              <Link href="#" className="flex items-center gap-1.5 text-sm text-gray-600 hover:text-gray-900 transition-colors">
                <Home className="w-4 h-4" />
                Buy
              </Link>
              <Link href="#" className="flex items-center gap-1.5 text-sm text-gray-600 hover:text-gray-900 transition-colors">
                <Building2 className="w-4 h-4" />
                Rent
              </Link>
              <Link href="#" className="flex items-center gap-1.5 text-sm text-gray-600 hover:text-gray-900 transition-colors">
                <Search className="w-4 h-4" />
                Sell
              </Link>
            </div>
          </div>

          <Link href="/" className="absolute left-1/2 -translate-x-1/2 flex items-center gap-2">
            <Image src="/images/logo.svg" alt="Millow" width={40} height={40} />
            <span className="text-xl font-bold">Millow</span>
          </Link>

          <div className="relative" ref={dropdownRef}>
            {account ? (
              <Button
                variant="outline"
                className="gap-2"
                onClick={() => setDropdownOpen(!dropdownOpen)}
              >
                <Wallet className="w-4 h-4" />
                {account.slice(0, 6)}...{account.slice(-4)}
                <ChevronDown className="w-3.5 h-3.5 text-muted-foreground" />
              </Button>
            ) : (
              <Button onClick={connectHandler} className="gap-2 bg-blue-600 hover:bg-blue-700">
                <Wallet className="w-4 h-4" />
                Connect Wallet
              </Button>
            )}

            {dropdownOpen && account && (
              <div className="absolute right-0 top-full mt-2 w-64 rounded-xl border bg-popover p-2 text-sm text-popover-foreground shadow-lg">
                <div className="px-3 py-2 border-b">
                  <p className="text-xs text-muted-foreground">Connected</p>
                  <p className="font-mono text-xs mt-0.5 break-all">{account}</p>
                </div>
                <button
                  onClick={copyAddress}
                  className="flex items-center gap-2 w-full rounded-lg px-3 py-2 hover:bg-muted transition-colors mt-1"
                >
                  <Copy className="w-4 h-4" />
                  Copy Address
                </button>
                <button
                  onClick={disconnectHandler}
                  className="flex items-center gap-2 w-full rounded-lg px-3 py-2 hover:bg-muted transition-colors text-red-500"
                >
                  <LogOut className="w-4 h-4" />
                  Disconnect
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    </motion.nav>
      <WalletModal
        open={walletModalOpen}
        onOpenChange={setWalletModalOpen}
        onConnect={handleWalletSelect}
      />
    </>
  )
}

export default Navigation
