'use client'

import { ethers } from 'ethers'
import { useEffect, useState } from 'react'
import { motion } from 'framer-motion'
import { Card, CardContent } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { Bed, Bath, Maximize, MapPin, ArrowRight } from 'lucide-react'
import Image from 'next/image'
import Navigation from '@/components/Navigation'
import Search from '@/components/Search'
import HomeDetail from '@/components/Home'
import config from '@/config.json'

export default function Home() {
  const [account, setAccount] = useState(null)
  const [provider, setProvider] = useState(null)
  const [escrow, setEscrow] = useState(null)
  const [homes, setHomes] = useState([])
  const [toggle, setToggle] = useState(false)
  const [home, setHome] = useState({})

  const loadBlockchainData = async () => {
    const provider = new ethers.providers.Web3Provider(window.ethereum)
    setProvider(provider)

    const network = await provider.getNetwork()
    const { address } = config[network.chainId.toString()]?.escrow || {}

    if (!address) {
      window.alert('Smart contract not deployed to detected network')
      return
    }

    const escrow = new ethers.Contract(
      address,
      (await import('@/abis/Escrow.json')).abi,
      provider
    )
    setEscrow(escrow)

    const realEstate = new ethers.Contract(
      config[network.chainId.toString()].realEstate.address,
      (await import('@/abis/RealEstate.json')).abi,
      provider
    )

    const supply = await realEstate.totalSupply()

    const homes = []
    for (let i = 0; i < supply; i++) {
      const tokenId = await realEstate.tokenByIndex(i)
      const tokenURI = await realEstate.tokenURI(tokenId)
      const response = await fetch(tokenURI)
      const metadata = await response.json()
      homes.push({ ...metadata, id: tokenId.toString() })
    }

    setHomes(homes)
  }

  const togglePop = (home) => {
    setHome(home)
    setToggle(!toggle)
  }

  useEffect(() => {
    if (typeof window.ethereum !== 'undefined') {
      loadBlockchainData()
    }
  }, [])

  return (
    <div className="min-h-screen bg-gradient-to-b from-gray-50 to-white">
      <Navigation account={account} setAccount={setAccount} setProvider={setProvider} />

      <main className="pt-16">
        <Search />

        <section className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pb-20">
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.5, delay: 0.4 }}
            className="mb-10"
          >
            <h2 className="text-2xl font-semibold text-gray-900">
              {account ? 'Available Properties' : 'Featured Properties'}
            </h2>
            <p className="text-gray-500 mt-1">
              {account ? 'Browse and invest in properties' : 'Connect your wallet to browse properties'}
            </p>
          </motion.div>

          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
            {homes.map((home, index) => (
              <motion.div
                key={home.id}
                initial={{ opacity: 0, y: 40 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.5, delay: 0.1 * index }}
                whileHover={{ y: -5 }}
              >
                <Card className="overflow-hidden cursor-pointer group" onClick={() => togglePop(home)}>
                  <div className="relative aspect-[4/3]">
                    <Image
                      src={home.image || '/images/houses.png'}
                      alt={home.name}
                      fill
                      className="object-cover transition-transform duration-300 group-hover:scale-105"
                    />
                    <div className="absolute top-3 left-3">
                      <Badge variant="secondary" className="bg-white/90 backdrop-blur-sm">
                        {home.attributes?.[0]?.value || '0'} ETH
                      </Badge>
                    </div>
                  </div>
                  <CardContent className="p-4">
                    <h3 className="font-semibold text-lg mb-1">{home.name}</h3>
                    <div className="flex items-center gap-1 text-sm text-gray-500 mb-3">
                      <MapPin className="w-3.5 h-3.5" />
                      <span className="truncate">{home.address}</span>
                    </div>
                    <div className="flex items-center gap-3 text-sm text-gray-600 mb-3">
                      <span className="flex items-center gap-1">
                        <Bed className="w-3.5 h-3.5" />
                        {home.attributes?.[2]?.value || 'N/A'} bds
                      </span>
                      <span className="flex items-center gap-1">
                        <Bath className="w-3.5 h-3.5" />
                        {home.attributes?.[3]?.value || 'N/A'} ba
                      </span>
                      <span className="flex items-center gap-1">
                        <Maximize className="w-3.5 h-3.5" />
                        {home.attributes?.[4]?.value || 'N/A'} sqft
                      </span>
                    </div>
                    <Button variant="ghost" className="w-full group" size="sm">
                      View Details
                      <ArrowRight className="w-3.5 h-3.5 ml-1 transition-transform group-hover:translate-x-1" />
                    </Button>
                  </CardContent>
                </Card>
              </motion.div>
            ))}
          </div>

          {homes.length === 0 && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.5 }}
              className="text-center py-20"
            >
              <p className="text-gray-500 text-lg">No properties found. Connect your wallet to load listings.</p>
            </motion.div>
          )}
        </section>
      </main>

      {toggle && (
        <HomeDetail
          home={home}
          provider={provider}
          account={account}
          escrow={escrow}
          togglePop={() => setToggle(false)}
        />
      )}
    </div>
  )
}
